import React from 'react';
import { useLocation } from 'react-router-dom';

export function MyTrip() {
  const location = useLocation();
  const tripResult = location.state?.tripResult; // Accessing tripResult from the state passed

  console.log("Trip result:", tripResult);

  return (
    <div className="py-8 w-11/12 mx-auto text-white bg-gray-800 rounded-lg shadow-md">
      <div>
        {/* Render trip details */}
        <h1 className="text-3xl font-bold mb-4">{trtrip_name}</h1>
        <p className="text-lg">{tripResult?.location}</p>
        <p className="text-lg">Duration: {tripResult?.duration}</p>
        <p className="text-lg">Budget: {tripResult?.budget}</p>

        {/* Example of rendering hotel options */}
        <h2 className="text-2xl font-semibold mt-6">Hotel Options:</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mt-4">
          {tripResult?.hotel_options?.map((hotel, index) => (
            <div key={index} className="bg-gray-700 p-4 rounded-lg">
              <img src={hotel?.hotel_image_url} alt={hotel?.hotel_name} className="w-full h-32 object-cover rounded-md" />
              <h3 className="text-xl font-semibold mt-4">{hotel?.hotel_name}</h3>
              <p>{hotel?.hotel_address}</p>
              <p>{hotel?.price_range}</p>
              <p>Rating: {hotel?.rating}</p>
              <p>{hotel?.description}</p>
            </div>
          ))}
        </div>

        {/* Example of rendering itinerary */}
        <h2 className="text-2xl font-semibold mt-6">Itinerary:</h2>
        <div className="mt-4">
          {Object.keys(tripResult?.itinerary || {}).map((day, index) => (
            <div key={index} className="mt-4">
              <h3 className="text-xl font-semibold">{tripResult?.itinerary[day]?.theme}</h3>
              <ul className="list-disc pl-6">
                {tripResult?.itinerary[day]?.activities?.map((activity, idx) => (
                  <li key={idx}>{activity}</li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
